mapper.select:
/* BibleSearchMapper.selectBibleBookOrdrList */ SELECT * FROM BIBLE_BOOK_ORDR WHERE 1=1
AND BOOK_AF = #{bookAf}
AND BOOK_AF = 'A'
ORDER BY BOOK_SEQ

/* BibleSearchMapper.selectBibleSearchList */
	SELECT * 
	FROM BIBLE_BOOK_ORDR A LEFT OUTER JOIN BIBLE_KORHRV B ON A.BOOK_SEQ = B.BOOK_SEQ
	WHERE 1=1
	AND A.BOOK_AF = #{bookAf}
	AND A.BOOK_SEQ = #{bookSeq}



				AND B.CHAPTER >= #{chapter}


				AND B.CHAPTER <= #{chapter2}


				AND B.VERSE >= #{verse}


				AND B.VERSE <= #{verse2}




				AND B.CHAPTER = #{chapter}


				AND B.VERSE = #{verse}





	AND B.CONTENT LIKE CONCAT ('%', #{searchKeyword},'%')

	ORDER BY B.CHAPTER, B.VERSE

/* BibleSearchMapper.selectBibleSearchList */
	select * from 
	(
	SELECT a.book_seq, a.book_nm, a.book_af, b.chapter, b.verse, b.content, CAST(concat(chapter,lpad(verse,3,0)) AS UNSIGNED) as se_ordr
	FROM BIBLE_BOOK_ORDR A LEFT OUTER JOIN BIBLE_KORHRV B ON A.BOOK_SEQ = B.BOOK_SEQ
	) a
	WHERE 1=1
	AND A.BOOK_AF = #{bookAf}
	AND A.BOOK_SEQ = #{bookSeq}


			and a.se_ordr between concat(nvl(nullif(#{chapter},''),1),lpad(nvl(nullif(#{verse},''),1),3,0)) and concat(nvl(nullif(#{chapter2},''),200),lpad(nvl(nullif(#{verse2},''),200),3,0))



				AND a.CHAPTER = #{chapter}


				AND a.VERSE = #{verse}




	AND a.CONTENT LIKE CONCAT ('%', #{searchKeyword},'%')

	ORDER BY a.se_ordr

/* BibleSearchMapper.selectBibleSearchJangCt */
	SELECT BOOK_SEQ, CHAPTER, COUNT(VERSE) AS VERSE_CT 
	FROM BIBLE_KORHRV
	WHERE 1=1
	AND BOOK_SEQ = #{bookSeq}

	AND CHAPTER = #{chapter}

	GROUP BY BOOK_SEQ, CHAPTER
